      'x-vercel-ip-country-region': 'CA',
      'x-vercel-ip-latitude': '37.7749',
      'x-vercel-ip-longitude': '-122.4194',
      'x-vercel-ip-timezone': 'America/Los_Angeles',
    })

    const result = geoFromHeaders(headers)

    assert.strictEqual(result.city, 'San Francisco')
    assert.strictEqual(result.country, 'United States')
    assert.strictEqual(result.countryCode, 'US')
    assert.strictEqual(result.region, 'CA')
    assert.strictEqual(result.latitude, '37.7749')
    assert.strictEqual(result.longitude, '-122.4194')
    assert.strictEqual(result.timezone, 'America/Los_Angeles')
  })

  it('returns undefined fields when no headers present', () => {
    const headers = new Headers()
    const result = geoFromHeaders(headers)

    assert.strictEqual(result.city, undefined)
    assert.strictEqual(result.country, undefined)
    assert.strictEqual(result.countryCode, undefined)
    assert.strictEqual(result.region, undefined)
    assert.strictEqual(result.latitude, undefined)
    assert.strictEqual(result.longitude, undefined)
    assert.strictEqual(result.timezone, undefined)
  })

  it('falls back to cf-ipcountry for countryCode', () => {
    const headers = new Headers({
      'cf-ipcountry': 'DE',
    })

    const result = geoFromHeaders(headers)

    assert.strictEqual(result.countryCode, 'DE')
    assert.strictEqual(result.country, 'Germany')
  })

  it('prefers x-vercel-ip-country over cf-ipcountry', () => {
    const headers = new Headers({
      'x-vercel-ip-country': 'FR',
      'cf-ipcountry': 'DE',
    })

    const result = geoFromHeaders(headers)

    assert.strictEqual(result.countryCode, 'FR')
    assert.strictEqual(result.country, 'France')
  })

  it('returns undefined country for unknown country codes', () => {
    const headers = new Headers({
      'x-vercel-ip-country': 'ZZ',
    })

    const result = geoFromHeaders(headers)

    assert.strictEqual(result.countryCode, 'ZZ')
    assert.strictEqual(result.country, undefined)
  })

  it('handles lowercase country code for COUNTRY_NAMES lookup', () => {
    const headers = new Headers({
      'x-vercel-ip-country': 'jp',
    })

    const result = geoFromHeaders(headers)

    assert.strictEqual(result.countryCode, 'jp')
    assert.strictEqual(result.country, 'Japan')
  })
})

describe('geo', () => {
  it('extracts geo from a request-like object', () => {
    const headers = new Headers({
      'x-vercel-ip-city': 'Tokyo',
      'x-vercel-ip-country': 'JP',
    })

    const result = geo({ headers })

    assert.strictEqual(result.city, 'Tokyo')
    assert.strictEqual(result.countryCode, 'JP')
    assert.strictEqual(result.country, 'Japan')
  })
})

describe('isInRegion', () => {
  it('returns true when countryCode matches a region', () => {
    const geoData: Geo = { countryCode: 'US' }
    assert.strictEqual(isInRegion(geoData, ['US', 'CA']), true)
  })

  it('matches case-insensitively', () => {
    const geoData: Geo = { countryCode: 'us' }
    assert.strictEqual(isInRegion(geoData, ['US', 'CA']), true)
  })

  it('matches when region list has lowercase', () => {
    const geoData: Geo = { countryCode: 'US' }
    assert.strictEqual(isInRegion(geoData, ['us', 'ca']), true)
  })

  it('returns false when countryCode does not match', () => {
    const geoData: Geo = { countryCode: 'DE' }
    assert.strictEqual(isInRegion(geoData, ['US', 'CA']), false)
  })

  it('returns false when countryCode is undefined', () => {
    const geoData: Geo = {}
    assert.strictEqual(isInRegion(geoData, ['US', 'CA']), false)
  })

  it('returns false for empty regions array', () => {
    const geoData: Geo = { countryCode: 'US' }
    assert.strictEqual(isInRegion(geoData, []), false)
  })
})

describe('geoDistance', () => {
  it('returns 0 for identical points', () => {
    const d = geoDistance(0, 0, 0, 0)
    assert.strictEqual(d, 0)
  })

  it('calculates distance between New York and London', () => {
    // NYC: 40.7128 N, 74.0060 W  London: 51.5074 N, 0.1278 W
    const d = geoDistance(40.7128, -74.006, 51.5074, -0.1278)
    // Expected ~5570 km
    assert.ok(d > 5500, `Expected > 5500, got ${d}`)
    assert.ok(d < 5650, `Expected < 5650, got ${d}`)
  })

  it('calculates distance between Tokyo and Sydney', () => {
    // Tokyo: 35.6762 N, 139.6503 E  Sydney: -33.8688 S, 151.2093 E
    const d = geoDistance(35.6762, 139.6503, -33.8688, 151.2093)
    // Expected ~7795 km
