    const headers = new Headers({
      'x-vercel-ip-country': 'FR',
      'cf-ipcountry': 'DE',
    })

    const result = geoFromHeaders(headers)

    assert.strictEqual(result.countryCode, 'FR')
    assert.strictEqual(result.country, 'France')
  })

  it('returns undefined country for unknown country codes', () => {
    const headers = new Headers({
      'x-vercel-ip-country': 'ZZ',
    })

    const result = geoFromHeaders(headers)

    assert.strictEqual(result.countryCode, 'ZZ')
    assert.strictEqual(result.country, undefined)
  })

  it('handles lowercase country code for COUNTRY_NAMES lookup', () => {
    const headers = new Headers({
      'x-vercel-ip-country': 'jp',
    })

    const result = geoFromHeaders(headers)

    assert.strictEqual(result.countryCode, 'jp')
    assert.strictEqual(result.country, 'Japan')
  })
