    assert.strictEqual(result.countryCode, 'JP')
    assert.strictEqual(result.country, 'Japan')
  })
})

describe('isInRegion', () => {
  it('returns true when countryCode matches a region', () => {
    const geoData: Geo = { countryCode: 'US' }
    assert.strictEqual(isInRegion(geoData, ['US', 'CA']), true)
  })

  it('matches case-insensitively', () => {
    const geoData: Geo = { countryCode: 'us' }
    assert.strictEqual(isInRegion(geoData, ['US', 'CA']), true)
  })

  it('matches when region list has lowercase', () => {
    const geoData: Geo = { countryCode: 'US' }
    assert.strictEqual(isInRegion(geoData, ['us', 'ca']), true)
  })

  it('returns false when countryCode does not match', () => {
    const geoData: Geo = { countryCode: 'DE' }
    assert.strictEqual(isInRegion(geoData, ['US', 'CA']), false)
  })

