    const d = geoDistance(40.7128, -74.006, 51.5074, -0.1278)
    // Expected ~5570 km
    assert.ok(d > 5500, `Expected > 5500, got ${d}`)
    assert.ok(d < 5650, `Expected < 5650, got ${d}`)
  })

