import assert from 'assert'
import { geo, geoFromHeaders, isInRegion, geoDistance } from './geo'

function test(name: string, fn: () => void) {
  try {
    fn()
    console.log(`✓ ${name}`)
  } catch (e: any) {
    console.error(`✗ ${name}`)
    console.error(e.message)
    process.exitCode = 1
  }
}

// --- geo() with Vercel headers ---

test('geo() extracts all Vercel headers', () => {
  const headers = new Headers({
    'x-vercel-ip-city': 'San Francisco',
    'x-vercel-ip-country': 'US',
    'x-vercel-ip-country-region': 'CA',
    'x-vercel-ip-latitude': '37.7749',
    'x-vercel-ip-longitude': '-122.4194',
    'x-vercel-ip-timezone': 'America/Los_Angeles',
  })

  const result = geo({ headers })
  assert.strictEqual(result.city, 'San Francisco')
  assert.strictEqual(result.countryCode, 'US')
  assert.strictEqual(result.country, 'United States')
  assert.strictEqual(result.region, 'CA')
  assert.strictEqual(result.latitude, '37.7749')
  assert.strictEqual(result.longitude, '-122.4194')
  assert.strictEqual(result.timezone, 'America/Los_Angeles')
})

// --- geoFromHeaders() with Cloudflare fallback ---

test('geoFromHeaders() uses Cloudflare cf-ipcountry as fallback for countryCode', () => {
  const headers = new Headers({
    'cf-ipcountry': 'DE',
  })

  const result = geoFromHeaders(headers)
  assert.strictEqual(result.countryCode, 'DE')
  assert.strictEqual(result.country, 'Germany')
  assert.strictEqual(result.city, undefined)
  assert.strictEqual(result.region, undefined)
  assert.strictEqual(result.latitude, undefined)
  assert.strictEqual(result.longitude, undefined)
  assert.strictEqual(result.timezone, undefined)
})

test('geoFromHeaders() prefers Vercel header over Cloudflare for countryCode', () => {
  const headers = new Headers({
    'x-vercel-ip-country': 'FR',
    'cf-ipcountry': 'DE',
  })

  const result = geoFromHeaders(headers)
  assert.strictEqual(result.countryCode, 'FR')
  assert.strictEqual(result.country, 'France')
})

// --- Missing headers ---

test('geo() returns undefined fields when headers are missing', () => {
  const headers = new Headers()
  const result = geo({ headers })
  assert.strictEqual(result.city, undefined)
  assert.strictEqual(result.country, undefined)
  assert.strictEqual(result.countryCode, undefined)
  assert.strictEqual(result.region, undefined)
  assert.strictEqual(result.latitude, undefined)
  assert.strictEqual(result.longitude, undefined)
  assert.strictEqual(result.timezone, undefined)
})

// --- Country name lookup ---

test('geo() looks up country name from countryCode', () => {
  const codes: Record<string, string> = {
    US: 'United States',
    GB: 'United Kingdom',
    DE: 'Germany',
    FR: 'France',
    JP: 'Japan',
    CN: 'China',
    IN: 'India',
    BR: 'Brazil',
    AU: 'Australia',
    CA: 'Canada',
  }

  for (const [code, name] of Object.entries(codes)) {
    const headers = new Headers({ 'x-vercel-ip-country': code })
    const result = geo({ headers })
    assert.strictEqual(result.country, name, `Expected ${name} for ${code}`)
  }
})

test('geo() returns undefined country for unknown countryCode', () => {
  const headers = new Headers({ 'x-vercel-ip-country': 'ZZ' })
  const result = geo({ headers })
  assert.strictEqual(result.countryCode, 'ZZ')
  assert.strictEqual(result.country, undefined)
})

// --- isInRegion() ---

test('isInRegion() returns true when countryCode matches a region', () => {
  const result = isInRegion({ countryCode: 'US' }, ['US', 'CA', 'GB'])
  assert.strictEqual(result, true)
})

test('isInRegion() is case-insensitive', () => {
  const result = isInRegion({ countryCode: 'us' }, ['US', 'CA'])
  assert.strictEqual(result, true)

  const result2 = isInRegion({ countryCode: 'US' }, ['us', 'ca'])
  assert.strictEqual(result2, true)
})

test('isInRegion() returns false when countryCode does not match', () => {
  const result = isInRegion({ countryCode: 'JP' }, ['US', 'CA', 'GB'])
  assert.strictEqual(result, false)
})

test('isInRegion() returns false when countryCode is undefined', () => {
  const result = isInRegion({}, ['US', 'CA'])
  assert.strictEqual(result, false)
})

// --- geoDistance() ---

test('geoDistance() calculates New York to London (~5570 km)', () => {
  // New York: 40.7128, -74.0060
  // London: 51.5074, -0.1278
  const distance = geoDistance('40.7128', '-74.0060', '51.5074', '-0.1278')
  assert.ok(
    Math.abs(distance - 5570) < 50,
    `Expected ~5570 km, got ${distance} km`
  )
})

test('geoDistance() returns 0 for same point', () => {
  const distance = geoDistance('37.7749', '-122.4194', '37.7749', '-122.4194')
  assert.strictEqual(distance, 0)
})

test('geoDistance() calculates Tokyo to Sydney (~7826 km)', () => {
  // Tokyo: 35.6762, 139.6503
  // Sydney: -33.8688, 151.2093
  const distance = geoDistance('35.6762', '139.6503', '-33.8688', '151.2093')
  assert.ok(
    Math.abs(distance - 7826) < 50,
    `Expected ~7826 km, got ${distance} km`
  )
})

console.log('\nAll geo tests completed.')

